  1	import * as React from 'react';
  2	import { connect } from 'react-redux';
  3	import { DurationDropdown } from '../Dropdown/DurationDropdown';
  4	import { Refresh } from 'components/Refresh/Refresh';
  5	import { KialiAppState } from 'store/Store';
  6	import { durationSelector, replayActiveSelector } from 'store/Selectors';
  7	import { DurationInSeconds } from 'types/Common';
  8	import { Tooltip, TooltipPosition, Button, ButtonVariant } from '@patternfly/react-core';
  9	import { KialiIcon } from 'config/KialiIcon';
 10	import { UserSettingsActions } from 'actions/UserSettingsActions';
 11	import { KialiDispatch } from 'types/Redux';
 12	import { bindActionCreators } from 'redux';
 13	import { kialiStyle } from 'styles/StyleUtils';
 14	import { useKialiTranslation } from 'utils/I18nUtils';
 15	
 16	type ReduxStateProps = {
 17	  duration: DurationInSeconds;
 18	  replayActive: boolean;
 19	};
 20	
 21	type ReduxDispatchProps = {
 22	  toggleReplayActive: () => void;
 23	};
 24	
 25	type TimeControlsProps = ReduxStateProps &
 26	  ReduxDispatchProps & {
 27	    disabled: boolean;
 28	    id: string;
 29	    supportsReplay?: boolean;
 30	  };
 31	
 32	const closeReplayStyle = kialiStyle({
 33	  marginLeft: '1rem'
 34	});
 35	
 36	const refreshStyle = kialiStyle({
 37	  marginLeft: '0.4rem',
 38	  marginRight: '0.4rem'
 39	});
 40	
 41	const TimeDurationComp: React.FC<TimeControlsProps> = (props: TimeControlsProps) => {
 42	  const { t } = useKialiTranslation();
 43	
 44	  const onToggleReplay = (): void => {
 45	    props.toggleReplayActive();
 46	  };
 47	
 48	  const durationTooltip = props.replayActive ? t('Traffic metrics per frame') : t('Traffic metrics per refresh');
 49	  const [prefix, suffix] = props.replayActive ? [undefined, t('Traffic')] : [t('Last'), undefined];
 50	
 51	  return (
 52	    <span>
 53	      {props.supportsReplay && !props.replayActive && (
 54	        <Tooltip key={'time_range_replay'} position={TooltipPosition.left} content={t('Replay...')}>
 55	          <Button
 56	            data-test="graph-replay-button"
 57	            variant={ButtonVariant.link}
 58	            style={{ padding: 0, marginRight: '0.5rem' }}
 59	            onClick={onToggleReplay}
 60	          >
 61	            <KialiIcon.History />
 62	            <span style={{ marginLeft: '0.5rem' }}>{t('Replay')}</span>
 63	          </Button>
 64	        </Tooltip>
 65	      )}
 66	
 67	      <DurationDropdown
 68	        id="time_range_duration"
 69	        disabled={props.disabled}
 70	        prefix={prefix}
 71	        suffix={suffix}
 72	        tooltip={durationTooltip}
 73	        tooltipPosition={TooltipPosition.left}
 74	      />
 75	
 76	      {!(props.supportsReplay && props.replayActive) && (
 77	        <Refresh className={refreshStyle} id="time_range_refresh" disabled={props.disabled} manageURL={true} />
 78	      )}
 79	
 80	      {props.supportsReplay && props.replayActive && (
 81	        <Button
 82	          data-test="graph-replay-close-button"
 83	          variant={ButtonVariant.link}
 84	          className={closeReplayStyle}
 85	          onClick={onToggleReplay}
 86	          isInline
 87	        >
 88	          <span>
 89	            <KialiIcon.Close />
 90	            <span style={{ marginLeft: '0.25rem' }}>{t('Close Replay')}</span>
 91	          </span>
 92	        </Button>
 93	      )}
 94	    </span>
 95	  );
 96	};
 97	
 98	const mapStateToProps = (state: KialiAppState): ReduxStateProps => ({
 99	  duration: durationSelector(state),
100	  replayActive: replayActiveSelector(state)
101	});
102	
103	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => ({
104	  toggleReplayActive: bindActionCreators(UserSettingsActions.toggleReplayActive, dispatch)
105	});
106	
107	export const TimeDurationComponent = connect(mapStateToProps, mapDispatchToProps)(TimeDurationComp);

